const now = new Date();
const d7 = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const d28 = new Date(now.getTime() - 28 * 24 * 60 * 60 * 1000);
return [{ json: {
  now: now.toISOString(),
  since7d: d7.toISOString(),
  since28d: d28.toISOString(),
  since7dDate: d7.toISOString().slice(0, 10),
  since28dDate: d28.toISOString().slice(0, 10),
  runDate: now.toISOString().slice(0, 10),
} }];

function rows(nodeName, idKey = 'id') {
  const out = [];
  for (const it of $(nodeName).all()) {
    const p = it && it.json;
    if (!p) continue;
    if (Array.isArray(p)) { for (const r of p) if (r && typeof r === 'object' && (idKey === null || r[idKey])) out.push(r); }
    else if (Array.isArray(p.data)) { for (const r of p.data) if (r && typeof r === 'object' && (idKey === null || r[idKey])) out.push(r); }
    else if (typeof p === 'object' && (idKey === null || p[idKey])) { out.push(p); }
  }
  return out;
}

const funnel = rows('Read posthog_daily_funnel', 'day');
const competitor = rows('Read competitor_watch 7d');
const partners = rows('Read partner_integrations');
const meta = $('Compute Window').first().json;

// Stale partners: status in (prospecting/negotiating) with no update in 30 days
const THIRTY_D = 30 * 24 * 60 * 60 * 1000;
const nowMs = Date.now();
const stalePartners = partners.filter(p => {
  if (!['prospecting','negotiating','contracted'].includes(p.status)) return false;
  const age = p.updated_at ? (nowMs - new Date(p.updated_at).getTime()) : 0;
  return age > THIRTY_D;
});

// Funnel drop-off detection (only if we have enough data)
const d7Funnel = funnel.slice(0, 7);
const d28Funnel = funnel.slice(0, 28);
const funnelHasData = d7Funnel.length >= 1;

const hasAnyData = funnelHasData || competitor.length > 0 || stalePartners.length > 0;

if (!hasAnyData) {
  return [{ json: {
    bypass_claude: true,
    note: 'no_weekly_data',
    summary: { d7_funnel_rows: 0, competitor_events_7d: 0, stale_partners: 0 },
    run_at: meta.now,
  }}];
}

const summary = {
  run_date: meta.runDate,
  d7_funnel_rows: d7Funnel.length,
  d28_funnel_rows: d28Funnel.length,
  competitor_events_7d: competitor.length,
  open_partners: partners.length,
  stale_partners_30d: stalePartners.length,
  stale_partner_names: stalePartners.slice(0, 10).map(p => p.partner_name),
};

const system = [
  'You are the Growth/Partnership agent for invest.com.au. You run weekly on Wednesday at 09:00 Sydney.',
  'Your job: surface funnel drop-off signals from PostHog, flag partnerships stuck > 30 days, summarise competitor activity, and propose up to 3 growth experiments for next week.',
  'Do NOT propose code changes directly (that is #02 CTO). Do NOT close partnerships (that is #06 BD or Co-Founder).',
  'When funnel data is sparse (<3 days), explicitly flag that in the digest rather than extrapolating.',
  '',
  'Return a JSON block (```json ... ```) with keys: headline (<=120 chars), funnel_observation (one string), top_experiments (array of up to 3 strings), stale_partnerships_to_nudge (array of partner_name strings), competitor_signals (array of up to 5 strings). Follow with a one-line digest.',
].join('\n');

const user = [
  `Run at: ${meta.now} (weekly brief)`,
  '',
  'Daily funnel rows (most recent 28 days, PostHog mirror view):',
  '```json',
  JSON.stringify(d28Funnel, null, 2),
  '```',
  '',
  'Competitor events in the last 7 days:',
  '```json',
  JSON.stringify(competitor.slice(0, 30), null, 2),
  '```',
  '',
  'Open partnerships (summary, most recently updated first):',
  '```json',
  JSON.stringify(partners.slice(0, 20), null, 2),
  '```',
  '',
  'Stale partnerships (> 30 days without status change):',
  '```json',
  JSON.stringify(stalePartners.slice(0, 10), null, 2),
  '```',
].join('\n');

return [{ json: {
  bypass_claude: false,
  system, user, summary, meta,
  run_at: meta.now,
}}];

const resp = $json || {};
const src = $('Build Growth prompt').item.json;

const textBlocks = Array.isArray(resp.content) ? resp.content.filter(c => c && c.type === 'text').map(c => c.text || '') : [];
const combined = textBlocks.join('\n');

let parsed = null;
const fence = combined.match(/```json\s*([\s\S]*?)```/i);
if (fence) { try { parsed = JSON.parse(fence[1].trim()); } catch (e) { parsed = null; } }
if (!parsed) {
  const brace = combined.match(/\{[\s\S]*\}/);
  if (brace) { try { parsed = JSON.parse(brace[0]); } catch (e) { parsed = null; } }
}

const headline = (parsed && typeof parsed.headline === 'string') ? parsed.headline.slice(0, 240) : 'Growth weekly digest';
const funnel_observation = (parsed && typeof parsed.funnel_observation === 'string') ? parsed.funnel_observation.slice(0, 600) : null;
const top_experiments = (parsed && Array.isArray(parsed.top_experiments)) ? parsed.top_experiments.slice(0, 3).map(s => String(s).slice(0, 400)) : [];
const stale_nudges = (parsed && Array.isArray(parsed.stale_partnerships_to_nudge)) ? parsed.stale_partnerships_to_nudge.slice(0, 10).map(s => String(s).slice(0, 200)) : [];
const competitor_signals = (parsed && Array.isArray(parsed.competitor_signals)) ? parsed.competitor_signals.slice(0, 5).map(s => String(s).slice(0, 400)) : [];

let level = 'info';
if (src.summary.stale_partners_30d > 0 || competitor_signals.length > 0) level = 'warn';

return [{ json: {
  agent_name: 'growth',
  level,
  message: headline,
  metadata: {
    weekly_digest: true,
    summary: src.summary,
    growth: {
      headline, funnel_observation, top_experiments, stale_nudges, competitor_signals,
      raw_text: combined.slice(0, 4000),
      model: resp.model || 'claude-opus-4-7',
      stop_reason: resp.stop_reason,
      usage: resp.usage,
    },
    run_at: src.run_at,
  },
}}];
